import{_ as e,o as t,c as n,ae as i}from"./chunks/framework.BGHOrOyn.js";const m=JSON.parse('{"title":"Making an SDR Antenna","description":"Making Antennas for 1090MHz ADS-B Aircraft Tracking","frontmatter":{"description":"Making Antennas for 1090MHz ADS-B Aircraft Tracking"},"headers":[],"relativePath":"software-defined-radio/making-an-sdr-antenna.md","filePath":"software-defined-radio/making-an-sdr-antenna.md"}'),r={name:"software-defined-radio/making-an-sdr-antenna.md"};function s(l,a,o,h,d,c){return t(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="making-an-sdr-antenna" tabindex="-1">Making an SDR Antenna <a class="header-anchor" href="#making-an-sdr-antenna" aria-label="Permalink to &quot;Making an SDR Antenna&quot;">​</a></h1><p>Page found on this link originally <a href="https://lucsmall.com/2017/02/06/making-antennas-for-1090mhz-ads-b-aircraft-tracking/" target="_blank" rel="noreferrer">https://lucsmall.com/2017/02/06/making-antennas-for-1090mhz-ads-b-aircraft-tracking/</a></p><p>Over the southern hemisphere summer of 2016/2017 I made a flurry of antennas tuned to 1090MHz to capture position information from aircraft ADS-B broadcasts. Here I document them, from newest to oldest.</p><p>The nice thing about making antennas for Gigahertz frequencies is that they tend to be rather compact. The wavelength of a 1090MHz transmission is approximately 275mm. Since the length of the antenna elements shares a relationship with the wavelength, this means you can make antennas with few materials, very inexpensively.</p><p>The newer antennas use F connectors to attach to my <a href="http://lucsmall.com/2017/02/01/ruggedised-usb-dvb-t-dongle-for-sdr/" target="_blank" rel="noreferrer">ruggedised USB DVB-T dongle</a>, which in turn connects to my <a href="http://lucsmall.com/2017/01/31/ruggedised-orange-pi-zero/" target="_blank" rel="noreferrer">ruggedised Orange Pi Zero</a> which <a href="http://lucsmall.com/2017/01/29/aircraft-tracking-with-the-orange-pi-zero/" target="_blank" rel="noreferrer">runs software to track aircraft</a>.</p><p><a href="https://lucsmall.com/images/2017-02-06-00-spider-antenna-by-night.png" target="_blank" rel="noreferrer"><img src="https://lucsmall.com/images/preview/2017-02-06-00-spider-antenna-by-night.png" alt="&quot;A 16 radial spider antenna for ADSB mounted on a tripod, at sunset&quot;"></a></p><h2 id="calculations" tabindex="-1">Calculations <a class="header-anchor" href="#calculations" aria-label="Permalink to &quot;Calculations&quot;">​</a></h2><p>Here are the relevant calculations:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wavelength</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> speed</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> light</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> frequency</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wavelength</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 299,792,000</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> m/s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1,090,000,000Hz</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wavelength</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0.275m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 275mm</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">half</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wavelength</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 137.5mm</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">quarter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wavelength</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 68.75mm</span></span></code></pre></div><p>For most antenna’s below, it’s the quarter wavelength measurement that we’re interested in. I round this up to <strong>69mm</strong> for convenience.</p><h3 id="_16-radial-spider" tabindex="-1">16 radial spider <a class="header-anchor" href="#_16-radial-spider" aria-label="Permalink to &quot;16 radial spider&quot;">​</a></h3><p>I think this is a good looking antenna, as far as antennas go. One 69mm wire forms the antenna, while sixteen 69mm wires bent downwards at 45° form the ground plane. They are soldered to a <a href="https://www.bunnings.com.au/kinetic-15mm-copper-capillary-end-cap_p4880053" target="_blank" rel="noreferrer">copper end cap</a> with a hole drilled in the middle for an F-connector. The wire is 1mm solid core electrical cable with the insulation stripped:</p><figure><img src="https://lucsmall.com/images/preview/2017-02-06-06-spider-antenna-16-radial.jpg" alt=""><figcaption></figcaption></figure><h3 id="_8-radial-spider" tabindex="-1">8 radial spider <a class="header-anchor" href="#_8-radial-spider" aria-label="Permalink to &quot;8 radial spider&quot;">​</a></h3><p>Before the 16 radial spider, there was this 8 radial spider built around the lid of a powdered stock tin. The antenna wire is 69mm. And the radials are 69mm long from the edge of the tin to their ends. They are bent downwards at approximately 45°. In the centre of the lid, I drilled a hole to accommodate an F-connector. The wire is 1mm solid core electrical cable with the insulation stripped.</p><p>I’m not entirely sure if the 69mm radial length should be measured from the edge of the tin lid (as I have done). Or whether they should be cut shorter to account for the ground plane effect of the tin lid. I’ve read that sometimes antenna radials are “tuned” (i.e. are sized to be resonant at the desired frequency) and at other times they are simply designed to be large with respect to the antenna. I’m not sure what’s best at 1090MHz; fodder for a future experiment, I guess.</p><figure><img src="https://lucsmall.com/images/preview/2017-02-06-05-spider-antenna-8-radial.jpg" alt=""><figcaption></figcaption></figure><h3 id="_4-radial-spider" tabindex="-1">4 radial spider <a class="header-anchor" href="#_4-radial-spider" aria-label="Permalink to &quot;4 radial spider&quot;">​</a></h3><p>Before the 8 radial spider was the 4 radial spider taking inspiration from <a href="http://discussions.flightaware.com/ads-b-flight-tracking-f21/three-easy-diy-antennas-for-beginners-t20177.html" target="_blank" rel="noreferrer">this post</a>. Very simple construction using a 69mm antenna and four 69mm radials soldered to a bulkhead BNC connector:</p><p><a href="https://lucsmall.com/images/2017-02-06-04-spider-antenna-4-radial.jpg" target="_blank" rel="noreferrer"><img src="https://lucsmall.com/images/preview/2017-02-06-04-spider-antenna-4-radial.jpg" alt="&quot;4 radial spider&quot;"></a></p><p>I was a bit miffed after making this antenna, because its performance seemed every bit as good as the coaxial collinear antenna I had made earlier, yet it took about a tenth of the time to build!</p><h3 id="the-coaxial-collinear-co-co" tabindex="-1">The coaxial collinear (co-co) <a class="header-anchor" href="#the-coaxial-collinear-co-co" aria-label="Permalink to &quot;The coaxial collinear (co-co)&quot;">​</a></h3><p>Wanting something better than the (albeit tuned) original antenna described next, I followed the instructions in my copy of the <a href="http://www.siliconchip.com.au/Issue/2013/September/Collinear+Antennas+For+Aircraft+ADS-B+Signals?res=nonflash" target="_blank" rel="noreferrer">September 2013 Sillicon Chip Magazine</a> to build this coax collinear (co-co) antenna:</p><p><a href="https://lucsmall.com/images/2017-02-06-03-coaxial-collinear.jpg" target="_blank" rel="noreferrer"><img src="https://lucsmall.com/images/preview/2017-02-06-03-coaxial-collinear.jpg" alt="&quot;Coaxial collinear antenna&quot;"></a></p><p>I used a coax stripper to very carefully cut 12 identical lengths of coax. I based the length of the sections (114mm each) on the half wavelength (137.5mm) scaled down by the velocity factor of the Belden RG6 coax cable (0.83) I was using. I assembled, terminated with a BNC socket, and housed the antenna inside electrical conduit.</p><p>The co-co antenna was better than the tuned original antenna. But after the very simple 4 radial spider performed just as well, I concluded that homebrew coaxial collinear antennas may just not be worth all the additional effort. That said, with greater accuracy in construction and perhaps different coax, I think they could give results. It’s just hard to achieve this accuracy with fairly basic tools and no network analyser to characterise the finished antenna.</p><p>A very similar design is described <a href="https://www.balarad.net/" target="_blank" rel="noreferrer">here</a>.</p><h3 id="a-tuned-the-stock-antenna" tabindex="-1">A tuned the stock antenna <a class="header-anchor" href="#a-tuned-the-stock-antenna" aria-label="Permalink to &quot;A tuned the stock antenna&quot;">​</a></h3><p>This was my first custom antenna. Taking the stock antenna and trimming it to 69mm. The improvement after trimming the antenna was noticeable.</p><p><a href="https://lucsmall.com/images/2017-02-06-02b-tuned-vs-untuned-antenna.jpg" target="_blank" rel="noreferrer"><img src="https://lucsmall.com/images/preview/2017-02-06-02b-tuned-vs-untuned-antenna.jpg" alt="&quot;Modified vs unmodified antenna&quot;"></a></p><p><a href="https://lucsmall.com/images/2017-02-06-02a-tuned-antenna.jpg" target="_blank" rel="noreferrer"><img src="https://lucsmall.com/images/preview/2017-02-06-02a-tuned-antenna.jpg" alt="&quot;Tuned antenna&quot;"></a></p><h3 id="the-stock-antenna" tabindex="-1">The stock antenna <a class="header-anchor" href="#the-stock-antenna" aria-label="Permalink to &quot;The stock antenna&quot;">​</a></h3><p>The stock antenna is 115mm long meaning it’s tuned for approximately 650MHz. Good, no doubt, for DVB-T broadcasts in many countries, but not an efficient antenna for ADS-B at 1090MHz. In spite of this, the stock antenna’s performance was surprisingly good. I was tracking 4 or so planes from inside my home the evening I first played with SDR. Talk about instant gratification.</p><p><a href="https://lucsmall.com/images/2017-02-06-01-original-antenna.jpg" target="_blank" rel="noreferrer"><img src="https://lucsmall.com/images/preview/2017-02-06-01-original-antenna.jpg" alt="&quot;Original antenna&quot;"></a>x</p><p>Posted by Luc Small Feb 6th, 2017</p>`,35)])])}const g=e(r,[["render",s]]);export{m as __pageData,g as default};
